// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  const [selectedForecastIndex, setSelectedForecastIndex] = useState<number>(0);

  const safeForecast = useMemo(() => {
    if (!Array.isArray(props.forecast)) {
      return Array.from({ length: 5 }, () => ({ day: undefined, icon: undefined, high: undefined, low: undefined }));
    }
    const trimmed = props.forecast.slice(0, 5);
    const placeholdersNeeded = Math.max(0, 5 - trimmed.length);
    return [
      ...trimmed,
      ...Array.from({ length: placeholdersNeeded }, () => ({ day: undefined, icon: undefined, high: undefined, low: undefined })),
    ];
  }, [props.forecast]);

  useEffect(() => {
    if (selectedForecastIndex > safeForecast.length - 1) {
      setSelectedForecastIndex(0);
    }
  }, [safeForecast.length, selectedForecastIndex]);

  const getConditionIcon = useCallback((condition: string | undefined) => {
    const normalized = (condition || '').toLowerCase();
    if (normalized.includes('sun') || normalized.includes('clear')) return '☀️';
    if (normalized.includes('cloud') || normalized.includes('overcast')) return '☁️';
    if (normalized.includes('rain') || normalized.includes('drizzle') || normalized.includes('shower')) return '🌧️';
    if (normalized.includes('storm') || normalized.includes('thunder')) return '⛈️';
    if (normalized.includes('snow') || normalized.includes('sleet') || normalized.includes('ice')) return '❄️';
    if (normalized.includes('fog') || normalized.includes('mist') || normalized.includes('haze')) return '🌫️';
    if (normalized.includes('wind')) return '💨';
    return '🌤️';
  }, []);

  const selectedForecast = safeForecast[selectedForecastIndex] || null;

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Card
        padding="var(--ggui-spacing-6)"
        shadow="md"
        radius="xl"
        border
      >
        <Stack gap="var(--ggui-spacing-5)">
          <Row justify="between" align="center" wrap>
            <Stack gap="var(--ggui-spacing-1)">
              <Heading level={2} color="var(--ggui-color-onSurface)">{props.city}</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">Current Weather</Text>
            </Stack>
            <Badge variant="primary" size="lg">{props.condition}</Badge>
          </Row>

          <Row justify="between" align="center" wrap>
            <Row align="center" gap="var(--ggui-spacing-3)">
              <Icon name={getConditionIcon(props.condition)} size={24} color="var(--ggui-color-primary-600)" aria-label={`${props.condition} icon`} />
              <Stack gap="var(--ggui-spacing-1)">
                <Text size="4xl" weight="bold" color="var(--ggui-color-onSurface)">
                  {props.temperature}°{props.unit}
                </Text>
                <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">{props.condition}</Text>
              </Stack>
            </Row>

            <Row gap="var(--ggui-spacing-4)" wrap>
              <Box
                padding="var(--ggui-spacing-3)"
                background="var(--ggui-color-surfaceVariant)"
                borderRadius="var(--ggui-shape-radius-md)"
              >
                <Stack gap="var(--ggui-spacing-1)">
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Humidity</Text>
                  <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface)">{props.humidity}%</Text>
                </Stack>
              </Box>
              <Box
                padding="var(--ggui-spacing-3)"
                background="var(--ggui-color-surfaceVariant)"
                borderRadius="var(--ggui-shape-radius-md)"
              >
                <Stack gap="var(--ggui-spacing-1)">
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Wind</Text>
                  <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface)">{props.windSpeed} km/h</Text>
                </Stack>
              </Box>
            </Row>
          </Row>

          <Divider margin="var(--ggui-spacing-2)" color="var(--ggui-color-outlineVariant)" />

          <Stack gap="var(--ggui-spacing-3)">
            <Heading level={3} color="var(--ggui-color-onSurface)">5-Day Forecast</Heading>

            {safeForecast.length === 0 ? (
              <Alert variant="info" title="No forecast available">
                Forecast data is currently unavailable.
              </Alert>
            ) : (
              <>
                <Row gap="var(--ggui-spacing-2)" wrap justify="start" align="start">
                  {safeForecast.map((item, index) => {
                    const isSelected = index === selectedForecastIndex;
                    return (
                      <Button
                        key={`${item.day || 'day'}-${index}`}
>
                        variant={isSelected ? 'primary' : 'outline'}
                        size="sm"
                        onClick={() => setSelectedForecastIndex(index)}
                        style={{ minWidth: '120px' }}
                      >
                        <Stack gap="var(--ggui-spacing-1)" align="center">
                          <Text variant="label" color="var(--ggui-color-onSurface)">{item.day || '—'}</Text>
                          {item.icon ? (
                            <Icon
                              name={item.icon}
                              size={20}
                              color="var(--ggui-color-primary-600)"
                              aria-hidden
                            />
                          ) : (
                            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">—</Text>
                          )}
                          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                            {item.high !== undefined ? `${item.high}°` : '—'} / {item.low !== undefined ? `${item.low}°` : '—'}
                          </Text>
                        </Stack>
                      </Button>
                    );
                  })}
                </Row>

                {selectedForecast && (
                  <Box
                    background="var(--ggui-color-primary-50)"
                    borderRadius="var(--ggui-shape-radius-md)"
                    padding="var(--ggui-spacing-3)"
                  >
                    <Row justify="between" align="center" wrap>
                      <Text variant="bodySmall" color="var(--ggui-color-primary-700)">
                        Selected: {selectedForecast.day}
                      </Text>
                      <Text variant="bodySmall" weight="medium" color="var(--ggui-color-primary-700)">
                        High {selectedForecast.high}° • Low {selectedForecast.low}°
                      </Text>
                    </Row>
                  </Box>
                )}
              </>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>

  );
}

