      setBoardTasks((prev) => prev.map((task) => (task.id === taskId ? { ...task, title: trimmed } : task)));
      try {
        taskUpdate({ action: 'edit', taskId, data: { column: current.column, title: trimmed } });
      } catch (_error) {
        setBoardTasks(previous);
        setErrorMessage('Could not save task title. Please try again.');
