        title: trimmed,
        priority: newTaskPriority,
        assignee: 'NA',
        column: columnId,
        dueDate: ''
      } as { id: string; title: string; priority: 'low' | 'medium' | 'high'; assignee: string; column: string; dueDate: string };
      const previous = boardTasks;
      setBoardTasks((prev) => [...prev, created]);
      pendingCreatesRef.current[trimmed] = id;
      try {
        taskUpdate({ action: 'create', taskId: id, data: { column: created.column, title: created.title, priority: created.priority, tempId: id } });
      } catch (_error) {
        setBoardTasks(previous);
        delete pendingCreatesRef.current[trimmed];
        setErrorMessage('Could not create task. Please try again.');
