            </Stack>
          </Card>
        ) : boardTasks.length === 0 && !Array.isArray(props.tasks) ? (
          <Card padding="var(--ggui-spacing-6)" shadow="sm">
            <Stack gap="var(--ggui-spacing-2)" align="center">
              <Spinner size={24} color="var(--ggui-color-primary-600)" />
              <Text color="var(--ggui-color-onSurfaceVariant)">Loading tasks...</Text>
            </Stack>
          </Card>
        ) : (
        <Row gap="var(--ggui-spacing-4)" align="start" wrap>
          {normalizedColumns.map((column) => {
            const tasksInColumn = boardTasks.filter((task) => task.column === column.id);
            return (
              <Card
                key={column.id}
                padding="var(--ggui-spacing-4)"
                shadow="sm"
                radius="lg"
                is="section"
                aria-labelledby={`column-heading-${column.id}`}
              >
                <Stack gap="var(--ggui-spacing-3)">
                  <Row justify="between" align="center">
                     <Heading level={4}>{column.name}</Heading>
                    <Badge variant="default">{tasksInColumn.length}</Badge>
                  </Row>

                  {tasksInColumn.length === 0 && (
                    <Text color="var(--ggui-color-onSurfaceVariant)">No tasks yet</Text>
                  )}

                  <Stack gap="var(--ggui-spacing-3)">
                    {tasksInColumn.map((task) => (
                      <Card key={task.id} padding="var(--ggui-spacing-3)" shadow="none" border radius="md">
                        <Stack gap="var(--ggui-spacing-2)">
                          <Row justify="between" align="start">
                            {editingTaskId === task.id ? (
                              <Stack gap="var(--ggui-spacing-2)">
                                <Input
                                  label="Edit task title"
                                  value={editingTitle}
                                  onChange={setEditingTitle}
                                  placeholder="Task title"
                                />
                                <Row gap="var(--ggui-spacing-2)">
