                                style={{ textDecoration: 'underline', color: 'var(--ggui-color-primary-700)' }}
                              >
                                {task.title}
                              </Text>
                            )}
                            <Button
                              size="sm"
                              variant="ghost"
                              onClick={() => {
                                setEditingTaskId(task.id);
                                setEditingTitle(task.title);
                              }}
                            >
                              Edit
                            </Button>
                          </Row>

                          <Row gap="var(--ggui-spacing-2)" align="center">
