interface Props {
  title: string; // Chat window title
  currentUser: string; // Current user name (for right-aligning own messages)
  participantCount: number; // Number of participants
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>; // Initial messages to display on mount
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag
  const [messageList, setMessageList] = useState<Array<{ sender?: string; text?: string; timestamp?: string }>>(props.messages ?? []);
  const [draft, setDraft] = useState<string>('');
  const [activeTyper, setActiveTyper] = useState<string>('');
  const [isLoadingMessages, setIsLoadingMessages] = useState<boolean>((props.messages ?? []).length === 0);
  const [sendError, setSendError] = useState<string>('');
  const [streamWarning, setStreamWarning] = useState<string>('');
  const scrollRef = useRef<HTMLDivElement | null>(null);
  const shouldAutoScrollRef = useRef<boolean>(true);

  const updateAutoScrollPreference = useCallback(() => {
    if (!scrollRef.current) return;
    const distanceFromBottom = scrollRef.current.scrollHeight - scrollRef.current.scrollTop - scrollRef.current.clientHeight;
    shouldAutoScrollRef.current = distanceFromBottom <= 80;
  }, []);

  useEffect(() => {
    setMessageList(props.messages ?? []);
    setIsLoadingMessages(false);
  }, [props.messages]);

  useEffect(() => {
    const unsubscribeMessage = message.subscribe((incoming) => {
      if (incoming && (incoming.text || incoming.sender || incoming.timestamp)) {
        setMessageList((prev) => [...prev, incoming as { sender?: string; text?: string; timestamp?: string }]);
      }
    });
    const unsubscribeTyping = typing.subscribe((incoming) => {
      if (incoming?.active) {
        setActiveTyper(incoming.sender ?? 'Someone');
      } else {
        setActiveTyper('');
      }
    });
    return () => {
      unsubscribeMessage?.();
      unsubscribeTyping?.();
    };
  }, [message, typing]);

  useEffect(() => {
    if (!scrollRef.current) return;
    if (!shouldAutoScrollRef.current && messageList.length > 0) return;
    scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messageList]);

  const groupedMessages = useMemo(() => {
    const groups: Array<{ sender?: string; items: Array<{ sender?: string; text?: string; timestamp?: string }> }> = [];
    messageList.forEach((item) => {
      const lastGroup = groups[groups.length - 1];
      if (lastGroup && lastGroup.sender === item.sender) {
        lastGroup.items.push(item);
      } else {
        groups.push({ sender: item.sender, items: [item] });
      }
    });
    return groups;
  }, [messageList]);

  const formatTime = useCallback((value?: string) => {
    if (!value) return '';
    const parsed = new Date(value);
    if (Number.isNaN(parsed.getTime())) return '';
    return parsed.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  }, []);

  const handleSend = useCallback(() => {
    const trimmed = draft.trim();
    if (!trimmed) return;
    const payload = { text: trimmed, timestamp: new Date().toISOString() };
    try {
      sendMessage(payload);
      setMessageList((prev) => [...prev, { sender: props.currentUser, text: payload.text, timestamp: payload.timestamp }]);
      setDraft('');
      setSendError('');
    } catch (error) {
      setSendError(error instanceof Error ? error.message : 'Failed to send message. Please try again.');
    }
  }, [draft, sendMessage, props.currentUser]);

  const handleKeyDown = useCallback(
    (event: React.KeyboardEvent<HTMLInputElement>) => {
      if (event.key === 'Enter' && !event.shiftKey) {
        event.preventDefault();
        handleSend();
      }
    },
    [handleSend]
  );

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Card
        padding="var(--ggui-spacing-4)"
        shadow="sm"
        border
      >
        <Stack gap="var(--ggui-spacing-4)">
          <Row justify="between" align="center">
            <Heading level={3} color="var(--ggui-color-onSurface)">{props.title}</Heading>
            <Row gap="var(--ggui-spacing-2)" align="center">
              <Badge variant="primary">{props.participantCount} participants</Badge>
            </Row>
          </Row>

          <Divider margin="0" color="var(--ggui-color-outlineVariant)" />

          <Box
            background="var(--ggui-color-surfaceVariant)"
            borderRadius="var(--ggui-shape-radius-md)"
            padding="var(--ggui-spacing-3)"
          >
            <Stack gap="var(--ggui-spacing-3)">
              {sendError ? <Alert variant="error">{sendError}</Alert> : null}
              {streamWarning ? <Alert variant="warning">{streamWarning}</Alert> : null}
              <Box
                ref={scrollRef}
                maxHeight="60vh"
                overflowY="auto"
                padding="var(--ggui-spacing-2)"
                background="var(--ggui-color-surface)"
                borderRadius="var(--ggui-shape-radius-md)"
                onScroll={updateAutoScrollPreference}
              >
                {isLoadingMessages ? (
                  <Row gap="var(--ggui-spacing-2)" align="center">
                    <Spinner size={16} />
                    <Text color="var(--ggui-color-onSurfaceVariant)">Loading messages…</Text>
                  </Row>
                ) : groupedMessages.length === 0 ? (
                  <Text color="var(--ggui-color-onSurfaceVariant)">No messages yet.</Text>
                ) : (
                  <Stack gap="var(--ggui-spacing-3)">
                    {groupedMessages.map((group, groupIndex) => {
                      const isOwn = group.sender === props.currentUser;
                      return (
                        <Stack key={`${group.sender ?? 'unknown'}-${groupIndex}`} gap="var(--ggui-spacing-1)" align={isOwn ? 'end' : 'start'}>
                          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{group.sender ?? 'Unknown'}</Text>
                          {group.items.map((msg, msgIndex) => (
                            <Box
                              key={`${groupIndex}-${msgIndex}-${msg.timestamp ?? ''}`}
                              background={isOwn ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)'}
                              borderRadius="var(--ggui-shape-radius-lg)"
                              padding="var(--ggui-spacing-2)"
                              maxWidth="75%"
                            >
                              <Stack gap="var(--ggui-spacing-1)">
                                <Text color={isOwn ? 'var(--ggui-color-onContainer)' : 'var(--ggui-color-onSurface)'}>{msg.text ?? ''}</Text>
                                <Text variant="caption" color={isOwn ? 'var(--ggui-color-primary-100)' : 'var(--ggui-color-onSurfaceVariant)'} align={isOwn ? 'right' : 'left'}>
                                  {formatTime(msg.timestamp)}
                                </Text>
                              </Stack>
                            </Box>
                          ))}
                        </Stack>
                      );
                    })}
                  </Stack>
                )}
              </Box>

              <Row justify="start" align="center">
                {activeTyper && activeTyper !== props.currentUser ? (
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{activeTyper} is typing...</Text>
                ) : null}
              </Row>

              <Divider margin="0" color="var(--ggui-color-outlineVariant)" />

              <Row gap="var(--ggui-spacing-2)" align="end">
                <Box flex="1">
                  <Input
                    label="Message"
                    placeholder="Type your message"
                    value={draft}
                    onChange={setDraft}
                    onKeyDown={handleKeyDown}
                  />
                </Box>
                <Button variant="primary" onClick={handleSend} disabled={!draft.trim()}>
                  Send
                </Button>
              </Row>
            </Stack>
          </Box>
        </Stack>
      </Card>
    </Container>

  );
}

