  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update
  const [stocksState, setStocksState] = useState<Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>>(props.stocks ?? []);
  const [lastUpdated, setLastUpdated] = useState<Date>(new Date());
  const [nowTick, setNowTick] = useState<number>(Date.now());
  const [flashMap, setFlashMap] = useState<Record<string, boolean>>({});
  const [announcement, setAnnouncement] = useState<string>('');
  const [isHydrating, setIsHydrating] = useState<boolean>((props.stocks ?? []).length === 0);
  useEffect(() => {
    setStocksState(props.stocks ?? []);
  }, [props.stocks]);


  useEffect(() => {
    if (!marketStatus.latest?.timestamp) {
      return;
    }
    const parsed = new Date(marketStatus.latest.timestamp);
    if (!Number.isNaN(parsed.getTime())) {
      setLastUpdated((prev) => (parsed.getTime() > prev.getTime() ? parsed : prev));
    }
  }, [marketStatus.latest?.timestamp]);

  useEffect(() => {
    if (!priceUpdate.latest || !priceUpdate.latest.symbol) {
      return;
    }
    const updateSymbol = priceUpdate.latest.symbol;
    setStocksState((prev) => {
      const exists = prev.some((stock) => stock.symbol === updateSymbol);
      if (!exists) {
        return prev;
      }
      return prev.map((stock) => {
        if (stock.symbol !== updateSymbol) {
          return stock;
        }
        return {
          ...stock,
          price: priceUpdate.latest?.price ?? stock.price,
          change: priceUpdate.latest?.change ?? stock.change,
          changePercent: priceUpdate.latest?.changePercent ?? stock.changePercent,
        };
      });
    });
    setLastUpdated(new Date());
    setAnnouncement(`${updateSymbol} updated to $${(priceUpdate.latest?.price ?? 0).toFixed(2)}, change ${(priceUpdate.latest?.change ?? 0) >= 0 ? '+' : ''}${(priceUpdate.latest?.change ?? 0).toFixed(2)} (${(priceUpdate.latest?.changePercent ?? 0) >= 0 ? '+' : ''}${(priceUpdate.latest?.changePercent ?? 0).toFixed(2)}%).`);
    setFlashMap((prev) => ({ ...prev, [updateSymbol]: true }));
    const flashTimer = setTimeout(() => {
      setFlashMap((prev) => ({ ...prev, [updateSymbol]: false }));
    }, 700);
    return () => clearTimeout(flashTimer);
  }, [priceUpdate.latest]);

