    const diffSeconds = Math.max(0, Math.floor((nowTick - lastUpdated.getTime()) / 1000));
    const recency = diffSeconds === 0 ? 'just now' : `${diffSeconds}s ago`;
    return `${lastUpdated.toLocaleTimeString()} (${recency})`;
  }, [lastUpdated, nowTick]);

