                Last Updated: {formattedUpdatedTime}
              </Text>
            </Stack>
            <Badge variant={marketStatusText === 'open' ? 'success' : marketStatusText === 'closed' ? 'error' : 'warning'}>
              {marketStatusText}
            </Badge>
          </Row>
        </Card>


        {isHydrating ? (
          <Card padding="var(--ggui-spacing-6)" border radius="lg">
            <Row justify="center" align="center">
              <Spinner size={24} color="var(--ggui-color-primary-600)" aria-label="Loading stock data" />
            </Row>
          </Card>

        ) : stocksState.length === 0 ? (
          <Card padding="var(--ggui-spacing-6)" border radius="lg">
            <Stack align="center" gap="var(--ggui-spacing-2)">
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                No stocks available.
              </Text>
            </Stack>
          </Card>
        ) : (
          <CardGrid columns={{ sm: 1, md: 3 }} gap={16}>
            {stocksState.map((stock, index) => {
              const symbol = stock.symbol ?? `stock-${index}`;
