              const arrow = isPositive ? '▲' : '▼';
              const trendColor = isPositive ? 'var(--ggui-color-success-500)' : 'var(--ggui-color-error-500)';
              const borderColor = isPositive ? 'var(--ggui-color-success-500)' : 'var(--ggui-color-error-500)';

              return (
                <Card
                  key={symbol}
                  padding="var(--ggui-spacing-3)"
                  radius="lg"
                  shadow="sm"
                  border
                >
                  <Box
                    padding="var(--ggui-spacing-3)"
                    background={flashMap[symbol] ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-surfaceVariant)'}
                    borderRadius="var(--ggui-shape-radius-md)"
                  >

                    <Stack gap="var(--ggui-spacing-2)">
                      <Heading level={3} color="var(--ggui-color-onSurface)">
                        {stock.symbol ?? 'N/A'}
                      </Heading>
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                        {stock.name ?? 'Unknown Company'}
