                          {arrow} {(stock.changePercent ?? 0) >= 0 ? '+' : ''}{(stock.changePercent ?? 0).toFixed(2)}%
                        </Text>
                      </Row>
                    </Stack>
                  </Box>
                </Card>
              );
            })}
          </CardGrid>
          )}
        {marketStatus.latest && marketStatus.latest.timestamp && Number.isNaN(new Date(marketStatus.latest.timestamp).getTime()) ? (
          <Alert variant="error" title="Live update error">
            Received malformed market status timestamp.
          </Alert>
        ) : null}
        <Text is="div" aria-live="polite" aria-atomic="true" aria-relevant="text" color="var(--ggui-color-onSurfaceVariant)" size="xs">
          {announcement}
        </Text>
      </Stack>
    </Container>

  );
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding
  const [step, setStep] = useState(1);
  const [name, setName] = useState(props.initialProfile.name ?? '');
  const [email, setEmail] = useState(props.initialProfile.email ?? '');
  const [avatar, setAvatar] = useState(props.initialProfile.avatar ?? (props.avatarOptions[0] ?? '😀'));
  const [role, setRole] = useState(props.initialProfile.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState(props.initialProfile.emailNotifications ?? false);
  const [theme, setTheme] = useState(props.initialProfile.theme === 'dark' ? 'dark' : 'light');

  const stepHeadingRef = useRef<HTMLHeadingElement | null>(null);
  const validEmail = useMemo(() => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim()), [email]);
  const stepOneValid = useMemo(() => name.trim().length > 0 && email.trim().length > 0 && validEmail && avatar.trim().length > 0, [name, email, validEmail, avatar]);
  const stepTwoValid = useMemo(() => role.trim().length > 0 && (theme === 'light' || theme === 'dark'), [role, theme]);
  const canGoNext = step === 1 ? stepOneValid : step < 3;

  const nextStep = useCallback(() => {
    if (step < 3 && canGoNext) setStep(step + 1);
  }, [step, canGoNext]);

  const prevStep = useCallback(() => {
    if (step > 1) setStep(step - 1);
  }, [step]);

  const onCompleteSetup = useCallback(() => {
    if (!stepOneValid || !stepTwoValid) return;
    const payload = {
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    };
    complete(payload);
  }, [name, email, avatar, role, emailNotifications, theme, stepOneValid, stepTwoValid, complete]);

  const progressValue = (step / 3) * 100;
  const emailError = email.trim().length === 0 ? 'Email is required' : validEmail ? '' : 'Enter a valid email address';
  const nameError = name.trim().length === 0 ? 'Name is required' : '';
  useEffect(() => {
    stepHeadingRef.current?.focus();
  }, [step]);
  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-4)" shadow="sm" border radius="lg">
          <Stack gap="var(--ggui-spacing-3)">
            <Row align="center" justify="between">
              <Heading level={1}>Onboarding Wizard</Heading>
              <Badge variant="primary">Step {step} of 3</Badge>
            </Row>
            <Progress value={progressValue} max={100} variant="default" size="md" />
          </Stack>
        </Card>

        <Card
          padding="var(--ggui-spacing-6)"
          shadow="md"
          border
          radius="lg"
        >
          <Box
            style={{
              animation: 'ggui-fadeIn 200ms ease-out',
            }}
          >
            {step === 1 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={2}>Profile Setup</Heading>
                <Input label="Name" value={name} onChange={setName} required error={nameError || undefined} placeholder="Enter your name" />
                <Input label="Email" type="email" value={email} onChange={setEmail} required error={emailError || undefined} placeholder="you@example.com" />
                <Stack gap="var(--ggui-spacing-2)">
                  <RadioGroup
                    label="Avatar"
                    value={avatar}
                    onChange={setAvatar}
                    options={(props.avatarOptions.length > 0 ? props.avatarOptions : ['😀', '🚀', '🎨', '🧠']).slice(0, 4).map((option) => ({ value: option, label: option }))}
                  />
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={2}>Preferences</Heading>
                <Select
                  label="Role"
                  value={role}
                  onChange={setRole}
                  placeholder="Select role"
                  options={(props.roleOptions.length > 0 ? props.roleOptions : ['Developer', 'Designer', 'Manager', 'Other']).map((r) => ({ value: r, label: r }))}
                  required
                  error={role.trim().length === 0 ? 'Role is required' : undefined}
                />
                <Toggle label="Email Notifications" checked={emailNotifications} onChange={setEmailNotifications} />
                <RadioGroup
                  label="Theme Preference"
                  value={theme}
                  onChange={setTheme}
                  direction="horizontal"
                  options={[
                    { value: 'light', label: 'Light' },
                    { value: 'dark', label: 'Dark' },
                  ]}
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={2}>Review & Confirm</Heading>
                <Card padding="var(--ggui-spacing-4)" border radius="md" shadow="none">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Row justify="between" wrap><Text variant="label">Name</Text><Text>{name}</Text></Row>
                    <Row justify="between" wrap><Text variant="label">Email</Text><Text>{email}</Text></Row>
                    <Row justify="between" wrap><Text variant="label">Avatar</Text><Text size="xl">{avatar}</Text></Row>
                    <Row justify="between" wrap><Text variant="label">Role</Text><Text>{role}</Text></Row>
                    <Row justify="between" wrap><Text variant="label">Notifications</Text><Text>{emailNotifications ? 'On' : 'Off'}</Text></Row>
                    <Row justify="between" wrap><Text variant="label">Theme</Text><Text>{theme}</Text></Row>
                  </Stack>
                </Card>
              </Stack>
            )}
          </Box>

          <Divider margin="var(--ggui-spacing-4)" />

          <Stack gap="var(--ggui-spacing-2)">
            <Row justify="between" align="center" wrap gap="var(--ggui-spacing-2)">
              <Button variant="ghost" onClick={prevStep} disabled={step === 1}>Back</Button>
              {step < 3 ? (
                <Button variant="primary" onClick={nextStep} disabled={!canGoNext}>Next</Button>
              ) : (
                <Row gap="var(--ggui-spacing-2)" wrap>
                  <Button variant="outline" onClick={prevStep}>Go Back</Button>
                  <Button variant="primary" onClick={onCompleteSetup} disabled={!stepOneValid || !stepTwoValid}>Complete Setup</Button>
                </Row>
              )}
            </Row>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" aria-live="polite">
              {`Currently on step ${step} of 3`
              }
            </Text>
          </Stack>

        </Card>
      </Stack>
    </Container>

  );
}
